public class OrderService {
    @Autowired
    private ApplicationEventPublisher publisher;

    @Transactional
    public void pay(Long orderId) {
        orderMapper.updateStatus(orderId, "PAID");
        publisher.publishEvent(new OrderPaidEvent(this, orderId));
    }
