    @MethodSource("provideDivisionData")
    void divideTest(int a, int b, int expected, Class<? extends Exception> exception) {
        if (exception != null) {
            assertThrows(exception, () -> calc.divide(a, b));
        } else {
            assertEquals(expected, calc.divide(a, b));
        }
    }

    static Stream<Arguments> provideDivisionData() {
        return Stream.of(
            Arguments.of(10, 2, 5, null),
            Arguments.of(10, 0, 0, ArithmeticException.class),
            Arguments.of(0, 5, 0, null)
        );
    }

