public class ProducerConsumer {
    private final BlockingQueue<String> queue = new LinkedBlockingQueue<>(100);
    private volatile boolean running = true;

    public void start() {
        // 生产者
        new Thread(() -> {
            int i = 0;
            while (running) {
                try {
                    String task = "Task-" + (++i);
                    queue.put(task);  // 队列满时阻塞
                    System.out.println("生产: " + task);
                    Thread.sleep(100);
                } catch (InterruptedException e) {
                    Thread.currentThread().interrupt();
                    break;
                }
            }
        }, "producer").start();

        // 消费者（多线程）
        for (int n = 0; n < 3; n++) {
            new Thread(() -> {
                while (running) {
                    try {
                        String task = queue.poll(2, TimeUnit.SECONDS);
                        if (task == null) continue;
                        System.out.println(Thread.currentThread().getName() + " 消费: " + task);
                        Thread.sleep(300);  // 模拟处理
                    } catch (InterruptedException e) {
                        Thread.currentThread().interrupt();
                        break;
                    }
                }
            }, "consumer-" + n).start();
        }
    }

    public void stop() {
        running = false;
    }
}

